const palette = {
  ink: "#03070F",
  night: "#06111E",
  nightLift: "#0A1B2B",
  panel: "#0D2234",
  panelBright: "#123047",
  white: "#F4FBFF",
  text: "#DDF3F7",
  muted: "#7E9EAD",
  faint: "#3E6271",
  cyan: "#39D8F5",
  cyanSoft: "#A4F4FF",
  teal: "#31E0C0",
  mint: "#78F3BB",
  violet: "#9B8CFF",
  amber: "#FFC86A",
  blue: "#5D8DFF",
  green: "#4BE49B",
};

const clamp = {
  extrapolateLeft: "clamp" as const,
  extrapolateRight: "clamp" as const,
};

const easeOut = Easing.bezier(0.16, 1, 0.3, 1);
const easeInOut = Easing.bezier(0.65, 0, 0.35, 1);

const phase = (
  frame: number,
  fps: number,
  startSeconds: number,
  endSeconds: number,
  easing: (value: number) => number = easeOut,
) =>
  interpolate(
    frame,
    [startSeconds * fps, endSeconds * fps],
    [0, 1],
    {...clamp, easing},
  );

const FullFrame: React.FC<{
  children?: React.ReactNode;
  style?: React.CSSProperties;
}> = ({children, style}) => (
  <div
    style={{
      position: "absolute",
      inset: 0,
      width: "100%",
      height: "100%",
      overflow: "hidden",
      display: "flex",
      ...style,
    }}
  >
    {children}
  </div>
);

type AgentType =
  | "plan"
  | "reason"
  | "research"
  | "memory"
  | "tools"
  | "execute"
  | "verify";

type AgentDatum = {
  type: AgentType;
  label: string;
  code: string;
  accent: string;
  angle: number;
};

const agents: AgentDatum[] = [
  {type: "plan", label: "PLAN", code: "A-01", accent: palette.cyan, angle: -90},
  {type: "reason", label: "REASON", code: "A-02", accent: palette.violet, angle: -38.57},
  {type: "research", label: "RESEARCH", code: "A-03", accent: palette.blue, angle: 12.86},
  {type: "memory", label: "MEMORY", code: "A-04", accent: palette.teal, angle: 64.29},
  {type: "tools", label: "TOOL USE", code: "A-05", accent: palette.amber, angle: 115.71},
  {type: "execute", label: "EXECUTE", code: "A-06", accent: palette.mint, angle: 167.14},
  {type: "verify", label: "VERIFY", code: "A-07", accent: palette.green, angle: 218.57},
];

