const Background: React.FC<{frame: number; fps: number}> = ({frame, fps}) => {
  const reveal = phase(frame, fps, 0, 1.2);
  const gridDrift = Math.sin(frame / 110) * 13;
  const scanX = interpolate(frame % (fps * 7.5), [0, fps * 7.5], [-420, 2280]);
  const particles = [
    {x: 112, y: 204, s: 3, d: 11},
    {x: 248, y: 812, s: 4, d: 73},
    {x: 411, y: 124, s: 2, d: 31},
    {x: 574, y: 918, s: 3, d: 103},
    {x: 1390, y: 153, s: 3, d: 58},
    {x: 1618, y: 294, s: 4, d: 7},
    {x: 1772, y: 815, s: 3, d: 89},
    {x: 1498, y: 946, s: 2, d: 42},
    {x: 923, y: 88, s: 2, d: 118},
    {x: 1018, y: 1001, s: 3, d: 25},
  ];

  return (
    <FullFrame
      style={{
        background:
          "radial-gradient(circle at 50% 46%, #123047 0%, #091A29 35%, #05101C 70%, #02060C 100%)",
      }}
    >
      <div
        style={{
          position: "absolute",
          inset: -90,
          width: 2100,
          height: 1260,
          opacity: reveal * 0.34,
          transform: `translate(${gridDrift}px, ${-gridDrift * 0.28}px) rotate(-1.2deg)`,
          backgroundImage:
            "linear-gradient(rgba(75,207,230,0.09) 1px, transparent 1px), linear-gradient(90deg, rgba(75,207,230,0.08) 1px, transparent 1px)",
          backgroundSize: "72px 72px",
          WebkitMaskImage:
            "radial-gradient(ellipse 72% 72% at 50% 50%, #000 12%, transparent 78%)",
          maskImage:
            "radial-gradient(ellipse 72% 72% at 50% 50%, #000 12%, transparent 78%)",
        }}
      />

      <div
        style={{
          position: "absolute",
          left: 960,
          top: 555,
          width: 1350,
          height: 740,
          transform: `translate(-50%, -50%) scale(${1 + Math.sin(frame / 94) * 0.018})`,
          borderRadius: "50%",
          background:
            "radial-gradient(ellipse, rgba(49,224,192,0.10), rgba(57,216,245,0.055) 42%, transparent 72%)",
          filter: "blur(16px)",
          opacity: reveal,
        }}
      />

      <div
        style={{
          position: "absolute",
          left: scanX,
          top: -120,
          width: 240,
          height: 1320,
          transform: "skewX(-18deg)",
          background:
            "linear-gradient(90deg, transparent, rgba(126,239,255,0.18), transparent)",
          filter: "blur(18px)",
          opacity: reveal * 0.22,
        }}
      />

      <div
        style={{
          position: "absolute",
          inset: 0,
          width: 1920,
          height: 1080,
          opacity: reveal * 0.22,
          background:
            "repeating-radial-gradient(circle at 50% 50%, transparent 0, transparent 88px, rgba(72,209,233,0.07) 89px, transparent 90px)",
          WebkitMaskImage:
            "radial-gradient(circle at 50% 50%, black, transparent 72%)",
          maskImage: "radial-gradient(circle at 50% 50%, black, transparent 72%)",
        }}
      />

      {particles.map((particle, index) => {
        const floatX = Math.sin((frame + particle.d) / 47) * 6;
        const floatY = Math.cos((frame + particle.d) / 39) * 8;
        const twinkle = 0.22 + (Math.sin((frame + particle.d) / 24) + 1) * 0.12;
        return (
          <div
            key={`${particle.x}-${particle.y}`}
            style={{
              position: "absolute",
              left: particle.x + floatX,
              top: particle.y + floatY,
              width: particle.s,
              height: particle.s,
              borderRadius: "50%",
              background: index % 3 === 0 ? palette.teal : palette.cyan,
              boxShadow: `0 0 ${particle.s * 4}px ${index % 3 === 0 ? palette.teal : palette.cyan}`,
              opacity: reveal * twinkle,
            }}
          />
        );
      })}

      <div
        style={{
          position: "absolute",
          inset: 0,
          width: 1920,
          height: 1080,
          boxShadow: "inset 0 0 170px 60px rgba(0,0,0,0.68)",
          pointerEvents: "none",
        }}
      />
    </FullFrame>
  );
};

type OrbitPosition = {
  x: number;
  y: number;
  scale: number;
  opacity: number;
  depth: number;
  angle: number;
};

const getOrbitPositions = (frame: number, durationInFrames: number): OrbitPosition[] => {
  const turn = (frame / durationInFrames) * 360;
  return agents.map((agent, index) => {
    const angle = ((agent.angle + turn) * Math.PI) / 180;
    const radiusNoise = index % 2 === 0 ? 1 : 0.975;
    const x = 960 + Math.cos(angle) * 510 * radiusNoise;
    const y = 548 + Math.sin(angle) * 305;
    const depth = (Math.sin(angle) + 1) / 2;
    return {
      x,
      y,
      angle,
      depth,
      scale: 0.84 + depth * 0.2,
      opacity: 0.62 + depth * 0.38,
    };
  });
};

const quadraticPoint = (
  sx: number,
  sy: number,
  cx: number,
  cy: number,
  ex: number,
  ey: number,
  t: number,
) => {
  const inv = 1 - t;
  return {
    x: inv * inv * sx + 2 * inv * t * cx + t * t * ex,
    y: inv * inv * sy + 2 * inv * t * cy + t * t * ey,
  };
};

const NetworkLines: React.FC<{
  frame: number;
  fps: number;
  positions: OrbitPosition[];
  activeIndex: number;
  sync: number;
}> = ({frame, fps, positions, activeIndex, sync}) => {
  const networkReveal = phase(frame, fps, 2.1, 4.1);
  const packetWindow =
    phase(frame, fps, 4.1, 4.55) * (1 - phase(frame, fps, 9.6, 10.05));
  const local = Math.max(0, frame - Math.round(4.15 * fps));
  const packetDuration = 50;
  const packetStep = local % packetDuration;
  const packetT = easeInOut(packetStep / packetDuration);
  const inbound = Math.floor(local / packetDuration) % 2 === 0;
  const routeT = inbound ? 1 - packetT : packetT;

  return (
    <svg
      width="1920"
      height="1080"
      viewBox="0 0 1920 1080"
      style={{position: "absolute", inset: 0, overflow: "visible"}}
    >
      <defs>
        <filter id="routeGlow" x="-80%" y="-80%" width="260%" height="260%">
          <feGaussianBlur stdDeviation="4.2" result="blur" />
          <feMerge>
            <feMergeNode in="blur" />
            <feMergeNode in="SourceGraphic" />
          </feMerge>
        </filter>
        <linearGradient id="orbitRail" x1="0" y1="0" x2="1" y2="1">
          <stop offset="0" stopColor={palette.violet} stopOpacity="0.08" />
          <stop offset="0.5" stopColor={palette.cyan} stopOpacity="0.6" />
          <stop offset="1" stopColor={palette.teal} stopOpacity="0.08" />
        </linearGradient>
      </defs>

      <ellipse
        cx="960"
        cy="548"
        rx="510"
        ry="305"
        fill="none"
        stroke="url(#orbitRail)"
        strokeWidth="1.4"
        strokeDasharray="6 15"
        strokeDashoffset={-frame * 0.55}
        opacity={0.74 * networkReveal}
      />
      <ellipse
        cx="960"
        cy="548"
        rx="475"
        ry="281"
        fill="none"
        stroke={palette.cyan}
        strokeWidth="0.8"
        strokeDasharray="1 20"
        strokeDashoffset={frame * 0.33}
        opacity={0.22 * networkReveal}
      />

      {positions.map((position, index) => {
        const dx = position.x - 960;
        const dy = position.y - 548;
        const length = Math.max(1, Math.sqrt(dx * dx + dy * dy));
        const bend = (index % 2 === 0 ? 1 : -1) * 26;
        const cx = 960 + dx * 0.52 - (dy / length) * bend;
        const cy = 548 + dy * 0.52 + (dx / length) * bend;
        const d = `M960 548 Q${cx.toFixed(2)} ${cy.toFixed(2)} ${position.x.toFixed(2)} ${position.y.toFixed(2)}`;
        const isActive = index === activeIndex;
        const intensity = isActive ? 1 : 0.42 + sync * 0.58;

        return (
          <g key={`route-${agents[index].type}`}>
            <path
              d={d}
              fill="none"
              stroke={agents[index].accent}
              strokeWidth="6"
              opacity={networkReveal * 0.06 * intensity}
              filter="url(#routeGlow)"
            />
            <path
              d={d}
              pathLength={1}
              fill="none"
              stroke={agents[index].accent}
              strokeWidth={isActive ? 2.2 : 1.15}
              strokeDasharray={isActive ? "0.12 0.055" : "0.03 0.065"}
              strokeDashoffset={-frame * (isActive ? 0.009 : 0.003)}
              opacity={networkReveal * (0.25 + intensity * 0.42)}
            />
            <path
              d={d}
              pathLength={1}
              fill="none"
              stroke={palette.white}
              strokeWidth="1.2"
              strokeDasharray={1}
              strokeDashoffset={1 - networkReveal}
              opacity={0.2 * networkReveal}
            />
          </g>
        );
      })}

      {packetWindow > 0 && (() => {
        const position = positions[activeIndex];
        const dx = position.x - 960;
        const dy = position.y - 548;
        const length = Math.max(1, Math.sqrt(dx * dx + dy * dy));
        const bend = (activeIndex % 2 === 0 ? 1 : -1) * 26;
        const cx = 960 + dx * 0.52 - (dy / length) * bend;
        const cy = 548 + dy * 0.52 + (dx / length) * bend;
        const point = quadraticPoint(960, 548, cx, cy, position.x, position.y, routeT);
        const trail = quadraticPoint(
          960,
          548,
          cx,
          cy,
          position.x,
          position.y,
          Math.min(1, Math.max(0, routeT + (inbound ? 0.045 : -0.045))),
        );
        return (
          <g opacity={packetWindow}>
            <line
              x1={trail.x}
              y1={trail.y}
              x2={point.x}
              y2={point.y}
              stroke={agents[activeIndex].accent}
              strokeWidth="7"
              strokeLinecap="round"
              opacity="0.22"
              filter="url(#routeGlow)"
            />
            <circle
              cx={point.x}
              cy={point.y}
              r="9"
              fill={agents[activeIndex].accent}
              opacity="0.2"
              filter="url(#routeGlow)"
            />
            <circle cx={point.x} cy={point.y} r="4.2" fill={palette.white} />
            <circle cx={point.x} cy={point.y} r="1.7" fill={agents[activeIndex].accent} />
          </g>
        );
      })()}
    </svg>
  );
};

